import{ax as n,A as a,aQ as r,z as i}from"./chunks/framework.BWRXlwpK.js";const g=JSON.parse('{"title":"Nuxt 基本介绍","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"nuxt/nuxt-intro.md","filePath":"nuxt/nuxt-intro.md"}'),l={name:"nuxt/nuxt-intro.md"};function o(e,t,s,u,x,p){return i(),a("div",null,t[0]||(t[0]=[r('<h1 id="nuxt-基本介绍" tabindex="-1">Nuxt 基本介绍 <a class="header-anchor" href="#nuxt-基本介绍" aria-label="Permalink to &quot;Nuxt 基本介绍&quot;">​</a></h1><p>Nuxt 是一个基于 Vue 的服务端渲染（SSR）和静态站点生成（SSG）的框架，旨再简化Vue应用开发的过程，同时提高性能和开发效率。它以 <strong>配置即开发</strong> （约定式）为理念，提供开箱即用的功能</p><h2 id="ssr-特点" tabindex="-1">SSR 特点 <a class="header-anchor" href="#ssr-特点" aria-label="Permalink to &quot;SSR 特点&quot;">​</a></h2><ul><li><strong>更快的初始页面加载时间</strong>： Nuxt 将完全渲染后的 HTML 页面发送到浏览器，可立即显示。这可以提供更快的感知加载速度和更好的用户体验 (UX)，特别是在网络较慢或设备性能较弱的情况下。</li><li><strong>改进的 SEO</strong>： 搜索引擎可以更好地索引 SSR 页面，因为 HTML 内容是即时可用的，而无需依赖客户端 JavaScript 来渲染内容。</li><li><strong>在低性能设备上表现更好</strong>： 它减少了需要在客户端下载和执行的 JavaScript 数量，这对可能难以处理大型 JavaScript 应用的低性能设备非常有益。</li><li><strong>更好的可访问性</strong>： 内容在初始页面加载时即可立即获取，从而改善了依赖屏幕阅读器或其他辅助技术用户的可访问性。</li><li><strong>更易于缓存</strong>： 页面可以在服务器端进行缓存，通过减少生成和发送内容给客户端所需的时间，进一步提高性能。</li></ul><p>总而言之，服务器端渲染可以提供更快、更高效的用户体验，同时还能提升搜索引擎优化 (SEO) 和可访问性。</p><h2 id="nuxt-特点" tabindex="-1">Nuxt 特点 <a class="header-anchor" href="#nuxt-特点" aria-label="Permalink to &quot;Nuxt 特点&quot;">​</a></h2><ul><li>基于文件路由：根据 <strong>app/pages</strong> 目录下的组件自动生成路由。</li><li>代码分割： Nuxt 会自动将您的代码分割成更小的块，这有助于减少应用程序的初始加载时间。</li><li>开箱即用的服务端渲染（SSR）: 不必在做繁琐的配置</li><li>自动导入：会将一些目录下的组件（如：components）自动导入到页面组件</li><li>数据获取工具：内置了很多组件、组合式函数以及工具函数</li><li>零配置的TypeScript支持</li><li>配置好的构建工具：默认使用 <strong>Vite</strong></li></ul><h2 id="nuxt-目录" tabindex="-1">Nuxt 目录 <a class="header-anchor" href="#nuxt-目录" aria-label="Permalink to &quot;Nuxt 目录&quot;">​</a></h2><ul><li>.nuxt：开发阶段 <strong>Nuxt</strong> 生成的临时目录。由 <strong>Nuxt</strong> 自动创建和管理，里面会存放和框架运行相关的代码和文件</li><li>.output：构建生产环境项目时产生，打包后的内容会存放在此目录</li><li>nuxt.config.ts：<strong>Nuxt</strong> 配置文件</li><li>app.vue：入口文件</li></ul>',9)]))}const d=n(l,[["render",o]]);export{g as __pageData,d as default};
